async function loadXLSX() { return await import('xlsx') }

async function parseXLSXFile(file) {
  const XLSX = await loadXLSX()
  const buf = await file.arrayBuffer()
  const wb = XLSX.read(buf, { type: 'array' })
  const ws = wb.Sheets[wb.SheetNames[0]]
  const rows = XLSX.utils.sheet_to_json(ws, { defval: '' })
  return { rows, headers: rows.length ? Object.keys(rows[0]) : [] }
}

function parseCSVText(txt) {
  const rows = []
  let line = [], field = '', inQ = false
  for (let i = 0; i <= txt.length; i++) {
    const ch = txt[i]
    if (i === txt.length || (ch === '\n' && !inQ)) {
      line.push(field); field = ''
      if (line.some(f => f.trim())) rows.push(line)
      line = []
    } else if (ch === '"') {
      if (inQ && txt[i+1] === '"') { field += '"'; i++ }
      else inQ = !inQ
    } else if (ch === ',' && !inQ) { line.push(field); field = '' }
    else if (ch !== '\r') field += ch
  }
  if (!rows.length) return []
  const hdrs = rows[0].map(h => h.trim())
  return rows.slice(1).map(r => {
    const o = {}
    hdrs.forEach((h, i) => o[h] = (r[i] || '').trim())
    return o
  })
}

function pick(row, ...keys) {
  for (const k of keys) {
    const found = Object.keys(row).find(h => h.toLowerCase().includes(k.toLowerCase()))
    if (found !== undefined && row[found] !== undefined && String(row[found]).trim() !== '') return String(row[found]).trim()
  }
  return ''
}

function mapRow(row) {
  return {
    _raw: row,
    email: pick(row,'email'),
    dept: pick(row,'function','team','dept','divisi'),
    purpose: pick(row,'purpose','tujuan'),
    tool_name: pick(row,'tool name','tool_name','nama tool','nama aplikasi'),
    problem: pick(row,'problem','solve','masalah','kendala'),
    how: pick(row,'how does it work','how it works','cara kerja','brief description'),
    prompt: pick(row,'prompt','copy paste'),
    html_file: pick(row,'upload','html file','ai submission'),
    demo: pick(row,'demo','screenshot','documentation'),
    deployed: pick(row,'deployed','share your ai submission link'),
  }
}

function hasHtmlFile(s) {
  const h = s.html_file || ''
  return h.length > 4 && (h.includes('drive.google') || (h.startsWith('http') && !h.includes('chatgpt') && !h.includes('claude.ai')))
}
function hasDeployedLink(s) {
  const d = s.deployed || ''
  return d.length > 3 && d !== '-' && d.startsWith('http') && !d.startsWith('file://') && !['chatgpt.com','suno.com','play.google','claude.ai'].some(x => d.includes(x))
}
function hasWorkingSubmission(s) { return hasHtmlFile(s) || hasDeployedLink(s) }
function getName(email) {
  return (email || '').split('@')[0].split('.').map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(' ')
}
function sleep(ms) { return new Promise(r => setTimeout(r, ms)) }

async function exportToXLSX(subs, results, originalRows, originalHeaders) {
  const XLSX = await loadXLSX()
  const newCols = ['Verdict','Intent Score','Prompt Score','HTML Score','AI Implementation Score','HTML File Uploaded','Summary','Action Required']
  const headers = [...originalHeaders, ...newCols]
  const VERDICT_LABEL = { good:'✅ Good to Go', review:'⚠️ Needs Revision', fail:'❌ Incomplete' }
  const data = subs.map((s, i) => {
    const r = results[i]
    const orig = originalRows[i] || {}
    const row = {}
    originalHeaders.forEach(h => { row[h] = orig[h] !== undefined ? orig[h] : '' })
    row['Verdict'] = r ? (VERDICT_LABEL[r.overall] || 'Pending') : 'Pending'
    row['Intent Score'] = r ? r.intent : ''
    row['Prompt Score'] = r ? r.prompt : ''
    row['HTML Score'] = r ? r.html : ''
    row['AI Implementation Score'] = r ? `${r.ai_score}/5` : ''
    row['HTML File Uploaded'] = hasHtmlFile(s) ? 'Yes' : 'No (deployed only)'
    row['Summary'] = r ? r.summary : ''
    row['Action Required'] = r ? r.action : ''
    return row
  })
  const ws = XLSX.utils.json_to_sheet(data, { header: headers })
  ws['!cols'] = headers.map(h => ({ wch: Math.max(h.length + 4, 20) }))
  const wb = XLSX.utils.book_new()
  XLSX.utils.book_append_sheet(wb, ws, 'Evaluation Results')
  XLSX.writeFile(wb, 'astro_ai_challenge_results.xlsx')
}

