const SCORE_STYLE = {
  full:    { bg:'#dcfce7', color:'#166534', icon:'✓' },
  partial: { bg:'#fef3c7', color:'#854d0e', icon:'~' },
  none:    { bg:'#fee2e2', color:'#991b1b', icon:'✗' },
}
function ScorePill({ score, label }) {
  const c = SCORE_STYLE[score] || SCORE_STYLE.none
  return <span style={{ display:'inline-flex', alignItems:'center', gap:3, padding:'2px 8px', borderRadius:10, fontSize:10, fontWeight:700, margin:1, background:c.bg, color:c.color }}>{c.icon} {label}</span>
}
function ScoreLabel({ score }) {
  const c = SCORE_STYLE[score] || SCORE_STYLE.none
  const labels = { full:'Fully Demonstrated', partial:'Partially Demonstrated', none:'Not Demonstrated' }
  return <span style={{ display:'inline-block', padding:'3px 10px', borderRadius:12, fontSize:11, fontWeight:600, background:c.bg, color:c.color }}>{labels[score] || '—'}</span>
}
function StarScore({ score }) {
  const n = parseInt(score) || 0
  return (
    <div style={{ display:'flex', alignItems:'center', gap:3 }}>
      {[1,2,3,4,5].map(i => (
        <span key={i} style={{ fontSize:14, color: i <= n ? '#f59e0b' : '#e2e8f0' }}>★</span>
      ))}
      <span style={{ fontSize:11, color:BRAND.textMuted, marginLeft:3 }}>{n}/5</span>
    </div>
  )
}
const VERDICT_STYLE = {
  good:    { bg:'#dcfce7', color:'#15803d', label:'✅ Good to Go' },
  review:  { bg:'#fef3c7', color:'#92400e', label:'⚠️ Needs Revision' },
  fail:    { bg:'#fee2e2', color:'#991b1b', label:'❌ Incomplete' },
  pending: { bg:'#f1f5f9', color:'#64748b', label:'Pending' },
}
function VerdictBadge({ verdict }) {
  const v = VERDICT_STYLE[verdict] || VERDICT_STYLE.pending
  return <span style={{ display:'inline-block', padding:'4px 10px', borderRadius:12, fontSize:11, fontWeight:700, whiteSpace:'nowrap', background:v.bg, color:v.color }}>{v.label}</span>
}

